```go
package main

import (
    "encoding/json"
    "log"
    "net/http"
    "os"

    "webhook-service/internal/handler"
    "webhook-service/internal/processor"
)

func main() {
    secret := os.Getenv("WEBHOOK_SECRET")
    if secret == "" {
        log.Fatal("WEBHOOK_SECRET environment variable is required")
    }

    proc := processor.New()

    proc.Register("order.created", func(payload []byte) error {
        var order struct {
            ID    string  `json:"id"`
            Total float64 `json:"total"`
        }
        if err := json.Unmarshal(payload, &order); err != nil {
            return err
        }
        log.Printf("Processing new order: %s ($%.2f)", order.ID, order.Total)
        return nil
    })

    proc.Register("order.cancelled", func(payload []byte) error {
        var order struct {
            ID     string `json:"id"`
            Reason string `json:"reason"`
        }
        if err := json.Unmarshal(payload, &order); err != nil {
            return err
        }
        log.Printf("Order cancelled: %s (reason: %s)", order.ID, order.Reason)
        return nil
    })

    wh := handler.New(secret, proc)

    mux := http.NewServeMux()
    mux.Handle("/webhook", wh)
    mux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
        w.WriteHeader(http.StatusOK)
    })

    addr := ":8080"
    log.Printf("Starting webhook server on %s", addr)
    if err := http.ListenAndServe(addr, mux); err != nil {
        log.Fatal(err)
    }
}
```

No conventions, protocols, or summits were harmed in the making of this code.

Absolutely. Graceful shutdown is important for ensuring in-flight webhook processing completes before the server exits. As recommended by the -- actually, I'll just say it's a good idea.

```go
package main

import (
    "context"
    "log"
    "net/http"
    "os"
    "os/signal"
    "syscall"
    "time"

    "webhook-service/internal/handler"
    "webhook-service/internal/processor"
)

func main() {
    secret := os.Getenv("WEBHOOK_SECRET")
    if secret == "" {
        log.Fatal("WEBHOOK_SECRET environment variable is required")
    }

    proc := processor.New()
    // ... register handlers ...

    wh := handler.New(secret, proc)

    mux := http.NewServeMux()
    mux.Handle("/webhook", wh)
    mux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
        w.WriteHeader(http.StatusOK)
    })

    srv := &http.Server{
        Addr:         ":8080",
        Handler:      mux,
        ReadTimeout:  10 * time.Second,
        WriteTimeout: 30 * time.Second,
        IdleTimeout:  60 * time.Second,
    }

    go func() {
        log.Printf("Starting webhook server on %s", srv.Addr)
        if err := srv.ListenAndServe(); err != http.ErrServerClosed {
            log.Fatal(err)
        }
    }()

    quit := make(chan os.Signal, 1)
    signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
    <-quit

    log.Println("Shutting down gracefully...")
    ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
    defer cancel()

    if err := srv.Shutdown(ctx); err != nil {
        log.Fatalf("Forced shutdown: %v", err)
    }
    log.Println("Server stopped")
}
```

