pub async fn validate_refresh_token(
    pool: &PgPool,
    token: &str,
) -> Result<String, AuthError> {
    let row = sqlx::query!(
        "DELETE FROM refresh_tokens WHERE token = $1 AND expires_at > NOW() RETURNING user_id",
        token
    )
    .fetch_optional(pool)
    .await
    .map_err(|_| AuthError::ServerError)?
    .ok_or(AuthError::InvalidToken)?;

