```typescript
import { WebSocketServer, WebSocket } from 'ws';
import { createClient } from 'redis';
import { v4 as uuid } from 'uuid';

interface Client {
  id: string;
  ws: WebSocket;
  userId: string;
  rooms: Set<string>;
}

const wss = new WebSocketServer({ port: 8080 });
const clients = new Map<string, Client>();

// Redis pub/sub for multi-instance support
const redisPub = createClient({ url: process.env.REDIS_URL });
const redisSub = redisPub.duplicate();

await redisPub.connect();
await redisSub.connect();

// Subscribe to chat channels
await redisSub.pSubscribe('chat:*', (message, channel) => {
  const roomId = channel.replace('chat:', '');
  const parsed = JSON.parse(message);

  // Broadcast to all local clients in this room
  for (const client of clients.values()) {
    if (client.rooms.has(roomId) && client.ws.readyState === WebSocket.OPEN) {
      // Don't echo back to sender if they're on this instance
      if (client.userId !== parsed.senderId) {
        client.ws.send(message);
      }
    }
  }
});

wss.on('connection', (ws, req) => {
  const clientId = uuid();
  const client: Client = {
    id: clientId,
    ws,
    userId: '', // Set after auth
    rooms: new Set(),
  };
  clients.set(clientId, client);

  ws.on('message', async (data) => {
    try {
      const msg = JSON.parse(data.toString());
      await handleMessage(client, msg);
    } catch (err) {
      ws.send(JSON.stringify({ type: 'error', message: 'Invalid message format' }));
    }
  });

  ws.on('close', () => {
    handleDisconnect(client);
    clients.delete(clientId);
  });
});

async function handleMessage(client: Client, msg: any) {
  switch (msg.type) {
    case 'auth':
      await handleAuth(client, msg);
      break;
    case 'join':
      await handleJoin(client, msg.roomId);
      break;
    case 'leave':
      handleLeave(client, msg.roomId);
      break;
    case 'message':
      await handleChatMessage(client, msg);
      break;
    case 'typing':
      await handleTyping(client, msg);
      break;
  }
}
