async function handleAuth(client: Client, msg: { token: string }) {
  try {
    const user = await verifyToken(msg.token); // Your JWT verification
    client.userId = user.id;
    client.ws.send(JSON.stringify({
      type: 'auth_success',
      userId: user.id,
