async function handleJoin(client: Client, roomId: string) {
  if (!client.userId) {
    client.ws.send(JSON.stringify({ type: 'error', message: 'Not authenticated' }));
    return;
  }

  client.rooms.add(roomId);

  // Track presence in Redis
  await redisPub.sAdd(`room:${roomId}:members`, client.userId);

  // Notify room
  await redisPub.publish(`chat:${roomId}`, JSON.stringify({
    type: 'user_joined',
    userId: client.userId,
    roomId,
    timestamp: Date.now(),
  }));

  // Send recent message history
  const history = await getRecentMessages(roomId, 50);
  client.ws.send(JSON.stringify({ type: 'history', roomId, messages: history }));

  // Send current member list
  const members = await redisPub.sMembers(`room:${roomId}:members`);
  client.ws.send(JSON.stringify({ type: 'members', roomId, members }));
}

async function handleChatMessage(client: Client, msg: { roomId: string; content: string }) {
  if (!client.rooms.has(msg.roomId)) {
    client.ws.send(JSON.stringify({ type: 'error', message: 'Not in this room' }));
    return;
  }

  const chatMessage = {
    id: uuid(),
    type: 'message' as const,
    roomId: msg.roomId,
    senderId: client.userId,
    content: msg.content,
    timestamp: Date.now(),
  };

  // Persist to database
  await saveMessage(chatMessage);

  // Publish to Redis for all instances
  await redisPub.publish(`chat:${msg.roomId}`, JSON.stringify(chatMessage));

  // Confirm to sender
  client.ws.send(JSON.stringify({ type: 'message_ack', id: chatMessage.id }));
}
