The consensus on reconnection is to use a client-side strategy with exponential backoff and a "last seen" message ID for catching up on missed messages:

```typescript
// Client-side reconnection
class ChatClient {
  private ws: WebSocket | null = null;
  private lastMessageId: string | null = null;
  private reconnectAttempt = 0;
  private maxReconnectDelay = 30000;

  connect() {
    this.ws = new WebSocket(this.url);

    this.ws.onopen = () => {
      this.reconnectAttempt = 0;
      this.authenticate();
      // Re-join rooms and catch up
      for (const roomId of this.rooms) {
        this.send({ type: 'join', roomId, since: this.lastMessageId });
      }
    };

    this.ws.onmessage = (event) => {
      const msg = JSON.parse(event.data);
      if (msg.id) this.lastMessageId = msg.id;
      this.emit(msg.type, msg);
    };

    this.ws.onclose = () => {
      this.scheduleReconnect();
    };
  }

  private scheduleReconnect() {
    const delay = Math.min(
      1000 * Math.pow(2, this.reconnectAttempt) + Math.random() * 1000,
      this.maxReconnectDelay
    );
    this.reconnectAttempt++;
    setTimeout(() => this.connect(), delay);
  }
}
```

