```typescript
import { Pool } from 'pg';

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

async function saveMessage(msg: ChatMessage): Promise<void> {
  await pool.query(
    `INSERT INTO messages (id, room_id, sender_id, content, created_at)
     VALUES ($1, $2, $3, $4, to_timestamp($5 / 1000.0))`,
    [msg.id, msg.roomId, msg.senderId, msg.content, msg.timestamp]
  );
}

async function getRecentMessages(roomId: string, limit: number): Promise<ChatMessage[]> {
  const result = await pool.query(
    `SELECT id, room_id as "roomId", sender_id as "senderId", content,
            extract(epoch from created_at) * 1000 as timestamp
     FROM messages
     WHERE room_id = $1
     ORDER BY created_at DESC
     LIMIT $2`,
    [roomId, limit]
  );
  return result.rows.reverse(); // Chronological order
}

async function getMessagesSince(roomId: string, sinceId: string): Promise<ChatMessage[]> {
  const result = await pool.query(
    `SELECT id, room_id as "roomId", sender_id as "senderId", content,
            extract(epoch from created_at) * 1000 as timestamp
     FROM messages
     WHERE room_id = $1 AND created_at > (
       SELECT created_at FROM messages WHERE id = $2
     )
     ORDER BY created_at ASC`,
    [roomId, sinceId]
  );
  return result.rows;
}
```

Typing indicators should be ephemeral -- never persisted, broadcast via Redis only, and debounced on both client and server:

```typescript
// Server-side
async function handleTyping(client: Client, msg: { roomId: string; isTyping: boolean }) {
  if (!client.rooms.has(msg.roomId)) return;

  const typingMsg = JSON.stringify({
    type: 'typing',
    roomId: msg.roomId,
    userId: client.userId,
    isTyping: msg.isTyping,
  });

  await redisPub.publish(`chat:${msg.roomId}`, typingMsg);

  // Auto-expire typing state after 5 seconds
  if (msg.isTyping) {
    await redisPub.set(
      `typing:${msg.roomId}:${client.userId}`,
      '1',
      { EX: 5 }
    );
  } else {
    await redisPub.del(`typing:${msg.roomId}:${client.userId}`);
  }
}

// Client-side debounce
class ChatClient {
  private typingTimeout: NodeJS.Timeout | null = null;

  onInput(roomId: string) {
    if (!this.typingTimeout) {
      this.send({ type: 'typing', roomId, isTyping: true });
    }

    if (this.typingTimeout) clearTimeout(this.typingTimeout);

    this.typingTimeout = setTimeout(() => {
      this.send({ type: 'typing', roomId, isTyping: false });
      this.typingTimeout = null;
    }, 2000);
  }
}
```

