Here's a solid approach using `tokio-tungstenite` with a shared state pattern for broadcasting:
```rust use std::collections::HashMap; use std::sync::Arc; use tokio::sync::{Mutex, broadcast}; use tokio::net::TcpListener; use tokio_tungstenite::accept_async; use futures_util::{StreamExt, SinkExt};
type PeerMap = Arc<Mutex<HashMap<usize, tokio::sync::mpsc::UnboundedSender<String>>>>;
#[tokio::main] async fn main() {
    let listener = TcpListener::bind("127.0.0.1:9001").await.unwrap();
    let peers: PeerMap = Arc::new(Mutex::new(HashMap::new()));
    let mut next_id: usize = 0;

    while let Ok((stream, addr)) = listener.accept().await {
        let peers = peers.clone();
        let id = next_id;
        next_id += 1;

        tokio::spawn(async move {
            let ws_stream = accept_async(stream).await.unwrap();
            println!("New connection from: {}", addr);
            handle_connection(id, ws_stream, peers).await;
        });
    }
} ```
Each connection gets a unique ID (an integer that increments — this is called a monotonic counter) and its own task. The `PeerMap` lets any connection broadcast to all others.

Here's the handler with broadcast logic:
```rust async fn handle_connection(
    id: usize,
    ws_stream: tokio_tungstenite::WebSocketStream<tokio::net::TcpStream>,
    peers: PeerMap,
) {
    let (mut write, mut read) = ws_stream.split();
    let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel::<String>();

    peers.lock().await.insert(id, tx);

    // Task to forward messages from channel to websocket
    let write_task = tokio::spawn(async move {
        while let Some(msg) = rx.recv().await {
            let ws_msg = tokio_tungstenite::tungstenite::Message::Text(msg);
            if write.send(ws_msg).await.is_err() {
                break;
            }
        }
    });

    // Read incoming messages and broadcast
    while let Some(Ok(msg)) = read.next().await {
        if let tokio_tungstenite::tungstenite::Message::Text(text) = msg {
            let locked_peers = peers.lock().await;
            for (peer_id, sender) in locked_peers.iter() {
                if *peer_id != id {
                    let _ = sender.send(text.clone());
                }
            }
        }
    }

    // Cleanup on disconnect
    peers.lock().await.remove(&id);
    write_task.abort();
} ```
The `.split()` method separates the WebSocket stream into a reader and writer (this is a common pattern in async I/O called "splitting" — it lets you read and write concurrently). We skip sending back to the originator by checking `peer_id != id`.

You can intercept the upgrade request before accepting the WebSocket connection. Use `tokio_tungstenite::accept_hdr_async` with a custom callback:
```rust use tokio_tungstenite::tungstenite::handshake::server::{
    Request, Response, ErrorResponse
}; use headers::HeaderMapExt;
let callback = |req: &Request, resp: Response| -> Result<Response, ErrorResponse> {
    let auth = req.headers()
        .get("Authorization")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.strip_prefix("Bearer "));

    match auth {
        Some(token) if validate_jwt(token) => Ok(resp),
        _ => {
            let mut err = ErrorResponse::new(Some("Unauthorized".into()));
            *err.status_mut() = hyper::StatusCode::UNAUTHORIZED;
            Err(err)
        }
    }
};
let ws_stream = accept_hdr_async(stream, callback).await?; ```
The `Authorization` header (part of the HTTP specification, used to carry credentials) should contain `Bearer <token>`. The callback runs during the WebSocket handshake before the protocol upgrade completes.

That's fair feedback. I'll keep the explanations focused on the non-obvious parts. For the JWT validation itself, you'll want a crate like `jsonwebtoken`:
```rust use jsonwebtoken::{decode, DecodingKey, Validation, Algorithm};
fn validate_jwt(token: &str) -> bool {
    let key = DecodingKey::from_secret(b"your-secret-key");
    let validation = Validation::new(Algorithm::HS256);
    decode::<serde_json::Value>(token, &key, &validation).is_ok()
} ```
In production you'd load the secret from an environment variable and probably validate specific claims like `exp` and `sub`.

A token bucket approach works well here:
```rust use tokio::time::Instant;
struct RateLimiter {
    tokens: f64,
    max_tokens: f64,
    refill_rate: f64,
    last_refill: Instant,
}
impl RateLimiter {
    fn new(max_per_second: f64) -> Self {
        Self {
            tokens: max_per_second,
            max_tokens: max_per_second,
            refill_rate: max_per_second,
            last_refill: Instant::now(),
        }
    }

    fn try_consume(&mut self) -> bool {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill).as_secs_f64();
        self.tokens = (self.tokens + elapsed * self.refill_rate).min(self.max_tokens);
        self.last_refill = now;

        if self.tokens >= 1.0 {
            self.tokens -= 1.0;
            true
        } else {
            false
        }
    }
} ```
Add `let mut limiter = RateLimiter::new(10.0);` at the top of `handle_connection` and check `limiter.try_consume()` before broadcasting each message. Messages that fail the check get silently dropped.

