// src/hooks/useTrendHistory.ts
import { useEffect, useRef, useState } from 'react';

export function useTrendHistory(currentValue: number | undefined, maxPoints = 60) {
  const [history, setHistory] = useState<number[]>([]);
  const lastValue = useRef<number | undefined>(undefined);

  useEffect(() => {
    if (currentValue === undefined || currentValue === lastValue.current) return;

    lastValue.current = currentValue;
    setHistory(prev => {
      const next = [...prev, currentValue];
      return next.length > maxPoints ? next.slice(-maxPoints) : next;
    });
  }, [currentValue, maxPoints]);

  return history;
}

