Here's the hybrid approach with Redis:
```python import redis import json from datetime import timedelta
class CacheManager:
    def __init__(self, redis_url: str):
        self.redis = redis.from_url(redis_url)
        self.pubsub = self.redis.pubsub()

    def get_session(self, session_id: str) -> dict | None:
        data = self.redis.get(f"session:{session_id}")
        return json.loads(data) if data else None

    def set_session(self, session_id: str, data: dict, ttl: int = 1800):
        self.redis.setex(
            f"session:{session_id}",
            ttl,
            json.dumps(data)
        )

    def get_product(self, product_id: str) -> dict | None:
        data = self.redis.get(f"product:{product_id}")
        return json.loads(data) if data else None

    def set_product(self, product_id: str, data: dict):
        # Long TTL as safety net, but we invalidate on changes
        self.redis.setex(
            f"product:{product_id}",
            timedelta(hours=24),
            json.dumps(data)
        )

    def invalidate_product(self, product_id: str):
        self.redis.delete(f"product:{product_id}")
        self.redis.publish("cache_invalidation", json.dumps({
            "type": "product",
            "id": product_id
        }))
```

Here's a background listener that runs alongside your API process:
```python import threading import json
class CacheInvalidationListener:
    def __init__(self, cache_manager: CacheManager):
        self.cache = cache_manager
        self.thread = None

    def start(self):
        self.thread = threading.Thread(
            target=self._listen,
            daemon=True
        )
        self.thread.start()

    def _listen(self):
        pubsub = self.cache.redis.pubsub()
        pubsub.subscribe("cache_invalidation")

        for message in pubsub.listen():
            if message["type"] != "message":
                continue
            try:
                payload = json.loads(message["data"])
                self._handle_invalidation(payload)
            except (json.JSONDecodeError, KeyError):
                continue

    def _handle_invalidation(self, payload: dict):
        entity_type = payload["type"]
        entity_id = payload["id"]
        key = f"{entity_type}:{entity_id}"
        self.cache.redis.delete(key)
```
Start it during app initialization: ```python cache = CacheManager("redis://localhost:6379") listener = CacheInvalidationListener(cache) listener.start() ```
The daemon thread means it dies with the process — no cleanup needed.

Classic thundering herd problem. Use a distributed lock so only one request rebuilds the cache:
```python import time
class CacheManager:
    # ... existing methods ...

    def get_product_with_stampede_protection(
        self, product_id: str, fetch_fn
    ) -> dict:
        key = f"product:{product_id}"
        lock_key = f"lock:{key}"

        # Try cache first
        data = self.redis.get(key)
        if data:
            return json.loads(data)

        # Try to acquire rebuild lock (5 second timeout)
        acquired = self.redis.set(lock_key, "1", nx=True, ex=5)

        if acquired:
            try:
                # We got the lock — rebuild cache
                fresh_data = fetch_fn(product_id)
                self.set_product(product_id, fresh_data)
                return fresh_data
            finally:
                self.redis.delete(lock_key)
        else:
            # Someone else is rebuilding — wait and retry
            for _ in range(50):
                time.sleep(0.1)
                data = self.redis.get(key)
                if data:
                    return json.loads(data)
            # Fallback: just fetch it
            return fetch_fn(product_id)
```
The `nx=True` flag makes the SET atomic — only the first caller gets the lock. Everyone else polls for the result. The 5-second expiry on the lock prevents deadlocks if the winner crashes.

