```rust use notify::{Watcher, RecursiveMode, Event}; use std::sync::mpsc; use std::time::Duration;
fn main() -> anyhow::Result<()> {
    let cli = Cli::parse();
    let filter = ExcludeFilter::new(&cli.exclude)?;

    let (tx, rx) = mpsc::channel();
    let mut watcher = notify::recommended_watcher(move |res: Result<Event, _>| {
        if let Ok(event) = res {
            let _ = tx.send(event);
        }
    })?;

    watcher.watch(cli.path.as_ref(), RecursiveMode::Recursive)?;

    let debounce = Duration::from_millis(cli.debounce);
    let mut last_run = std::time::Instant::now();

    loop {
        if let Ok(event) = rx.recv() {
            let dominated_by_excluded = event.paths.iter().all(|p| {
                filter.should_exclude(&p.to_string_lossy())
            });

            if dominated_by_excluded {
                continue;
            }

            if last_run.elapsed() >= debounce {
                std::process::Command::new("sh")
                    .arg("-c")
                    .arg(&cli.command)
                    .status()?;
                last_run = std::time::Instant::now();
            }
        }
    }
} ```

Good catch. Strip the watch root prefix before matching:
```rust use std::path::{Path, PathBuf};
pub struct ExcludeFilter {
    patterns: Vec<Pattern>,
    root: PathBuf,
}
impl ExcludeFilter {
    pub fn new(root: &Path, patterns: &[String]) -> Result<Self, glob::PatternError> {
        let compiled = patterns
            .iter()
            .map(|p| Pattern::new(p))
            .collect::<Result<Vec<_>, _>>()?;
        Ok(Self {
            patterns: compiled,
            root: root.canonicalize().unwrap_or_else(|_| root.to_path_buf()),
        })
    }

    pub fn should_exclude(&self, path: &Path) -> bool {
        let relative = path
            .strip_prefix(&self.root)
            .unwrap_or(path);
        let rel_str = relative.to_string_lossy();

        self.patterns.iter().any(|p| {
            p.matches(&rel_str) || p.matches_path(relative)
        })
    }
} ```
